"use client";

import {
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  type CSSProperties,
} from "react";
import * as THREE from "three";
import gsap from "gsap";

const vert = /* glsl */ `
  uniform vec2  uMouse;
  uniform float uHover;
  uniform float uAspect;

  varying vec2 vUv;

  void main() {
    vUv = uv;
    vec3 pos = position;

    vec2 acDelta = (uv - uMouse) * vec2(uAspect, 1.0);
    float dist   = length(acDelta);

    float infl = exp(-dist * dist * 6.0) * uHover;

    vec2 dir  = dist > 0.001 ? acDelta / dist : vec2(0.0);
    float mag = infl * 0.2;

    pos.x += (dir.x / uAspect) * mag;
    pos.y += dir.y * mag;

    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
  }
`;

const frag = /* glsl */ `
  precision highp float;
  uniform sampler2D uTex;
  varying vec2 vUv;

  void main() {
    gl_FragColor = texture2D(uTex, vUv);
  }
`;

const HERO_TEXT = "Francis Oliver \u2014";

/** Stable mask box through intro → WebGL handoff (avoids vertical reflow when outers lose GSAP padding). */
const CHAR_OUTER_MASK_STYLE: CSSProperties = {
  verticalAlign: "bottom",
  overflow: "hidden",
  paddingTop: "0.15em",
  marginTop: "-0.15em",
  paddingBottom: "0.22em",
  marginBottom: "-0.22em",
  paddingLeft: "0.06em",
  marginLeft: "-0.06em",
  paddingRight: "0.06em",
  marginRight: "-0.06em",
};

type Props = {
  playIntro?: boolean;
  holdForIntro?: boolean;
  onIntroComplete?: () => void;
};

export default function HeroText({
  playIntro = false,
  holdForIntro = false,
  onIntroComplete,
}: Props) {
  const wrapRef = useRef<HTMLDivElement>(null);
  const h1Ref = useRef<HTMLHeadingElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const textColorRef = useRef("rgb(0, 0, 0)");
  const introRanRef = useRef(false);
  const onCompleteRef = useRef(onIntroComplete);
  const [shaderReady, setShaderReady] = useState(false);
  const redrawRef = useRef<(() => void) | null>(null);

  useEffect(() => {
    onCompleteRef.current = onIntroComplete;
  }, [onIntroComplete]);

  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) canvas.style.opacity = "0";
    if (!holdForIntro) return;
    const wrap = wrapRef.current;
    if (wrap) wrap.style.visibility = "hidden";
  }, [holdForIntro]);

  useEffect(() => {
    let alive = true;
    let teardown: (() => void) | null = null;

    (async () => {
      await document.fonts.ready;
      if (!alive) return;

      const wrap = wrapRef.current;
      const h1 = h1Ref.current;
      const canvas = canvasRef.current;
      if (!wrap || !h1 || !canvas) return;

      textColorRef.current = getComputedStyle(h1).color || "rgb(0, 0, 0)";

      const measure = () => {
        const rect = h1.getBoundingClientRect();
        const dpr = devicePixelRatio || 1;
        return {
          rect,
          dpr,
          W: Math.max(1, Math.round(rect.width * dpr)),
          H: Math.max(1, Math.round(rect.height * dpr)),
          aspect: rect.width && rect.height ? rect.width / rect.height : 1,
        };
      };

      const { rect } = measure();
      let { dpr, W, H, aspect } = measure();
      if (!rect.width || !rect.height) return;

      const off = document.createElement("canvas");
      off.width = W;
      off.height = H;
      const ctx = off.getContext("2d")!;

      const drawText = (r: DOMRect, d: number) => {
        const cs = getComputedStyle(h1);
        const text =
          cs.textTransform === "uppercase"
            ? HERO_TEXT.toUpperCase()
            : HERO_TEXT;

        ctx.setTransform(d, 0, 0, d, 0, 0);
        ctx.clearRect(0, 0, off.width, off.height);
        ctx.font = `${cs.fontWeight} ${cs.fontSize} ${cs.fontFamily}`;
        ctx.fillStyle = textColorRef.current;
        ctx.textBaseline = "middle";

        const charSpans = h1.querySelectorAll<HTMLElement>(".char-inner");
        if (charSpans.length >= text.length) {
          charSpans.forEach((span, idx) => {
            if (idx >= text.length) return;
            const sr = span.getBoundingClientRect();
            ctx.fillText(
              text[idx]!,
              sr.left - r.left,
              sr.top - r.top + sr.height / 2,
            );
          });
        } else {
          const ls = parseFloat(cs.letterSpacing) || 0;
          const padL = parseFloat(cs.paddingLeft) || 0;
          let x = padL;
          for (const ch of text) {
            ctx.fillText(ch, x, r.height / 2);
            x += ctx.measureText(ch).width + ls;
          }
        }
      };
      drawText(rect, dpr);

      const renderer = new THREE.WebGLRenderer({
        canvas,
        alpha: true,
        antialias: false,
      });
      renderer.setSize(W, H, false);
      renderer.setPixelRatio(1);

      const scene = new THREE.Scene();
      const cam = new THREE.OrthographicCamera(
        -0.5, 0.5, 0.5, -0.5, 0.01, 10,
      );
      cam.position.z = 1;

      const tex = new THREE.CanvasTexture(off);
      tex.minFilter = THREE.LinearFilter;
      tex.magFilter = THREE.LinearFilter;

      const uniforms = {
        uTex: { value: tex },
        uMouse: { value: new THREE.Vector2(-1, -1) },
        uHover: { value: 0 as number },
        uAspect: { value: aspect },
      };

      const segX = Math.min(200, Math.max(64, Math.round(W / 6)));
      const segY = Math.min(50, Math.max(10, Math.round(H / 6)));
      const geo = new THREE.PlaneGeometry(1, 1, segX, segY);
      const mat = new THREE.ShaderMaterial({
        vertexShader: vert,
        fragmentShader: frag,
        uniforms,
        transparent: true,
      });
      scene.add(new THREE.Mesh(geo, mat));

      setShaderReady(true);
      redrawRef.current = () => {
        const m = measure();
        if (!m.rect.width || !m.rect.height) return;
        drawText(m.rect, m.dpr);
        tex.needsUpdate = true;
        renderer.render(scene, cam);
      };

      let tX = -1;
      let tY = -1;
      const LERP = 0.1;

      let rafId = 0;
      const loop = () => {
        rafId = requestAnimationFrame(loop);
        const m = uniforms.uMouse.value;
        m.x += (tX - m.x) * LERP;
        m.y += (tY - m.y) * LERP;
        renderer.render(scene, cam);
      };
      loop();

      const toUV = (e: MouseEvent) => {
        const r = h1.getBoundingClientRect();
        return {
          x: (e.clientX - r.left) / r.width,
          y: 1 - (e.clientY - r.top) / r.height,
        };
      };

      const onEnter = (e: MouseEvent) => {
        const uv = toUV(e);
        tX = uniforms.uMouse.value.x = uv.x;
        tY = uniforms.uMouse.value.y = uv.y;
        gsap.killTweensOf(uniforms.uHover);
        gsap.to(uniforms.uHover, {
          value: 1,
          duration: 0.3,
          ease: "power2.out",
        });
      };
      const onMove = (e: MouseEvent) => {
        const uv = toUV(e);
        tX = uv.x;
        tY = uv.y;
      };
      const onLeave = () => {
        gsap.killTweensOf(uniforms.uHover);
        gsap.to(uniforms.uHover, {
          value: 0,
          duration: 0.45,
          ease: "power2.inOut",
          onComplete: () => {
            tX = uniforms.uMouse.value.x = -1;
            tY = uniforms.uMouse.value.y = -1;
          },
        });
      };

      wrap.addEventListener("mouseenter", onEnter);
      wrap.addEventListener("mousemove", onMove);
      wrap.addEventListener("mouseleave", onLeave);

      let resizeRaf = 0;
      const syncSize = () => {
        const m = measure();
        if (!m.rect.width || !m.rect.height) return;
        if (m.W !== W || m.H !== H || m.dpr !== dpr) {
          W = m.W;
          H = m.H;
          dpr = m.dpr;
          aspect = m.aspect;
          off.width = W;
          off.height = H;
          drawText(m.rect, dpr);
          tex.needsUpdate = true;
          renderer.setSize(W, H, false);
          uniforms.uAspect.value = aspect;
        }
      };
      const requestSync = () => {
        cancelAnimationFrame(resizeRaf);
        resizeRaf = requestAnimationFrame(syncSize);
      };
      const ro = new ResizeObserver(requestSync);
      ro.observe(h1);
      window.addEventListener("resize", requestSync);

      teardown = () => {
        cancelAnimationFrame(resizeRaf);
        cancelAnimationFrame(rafId);
        ro.disconnect();
        window.removeEventListener("resize", requestSync);
        wrap.removeEventListener("mouseenter", onEnter);
        wrap.removeEventListener("mousemove", onMove);
        wrap.removeEventListener("mouseleave", onLeave);
        redrawRef.current = null;
        setShaderReady(false);
        renderer.dispose();
        tex.dispose();
        mat.dispose();
        geo.dispose();
      };
    })();

    return () => {
      alive = false;
      teardown?.();
    };
  }, []);

  useEffect(() => {
    if (holdForIntro) return;
    if (!shaderReady) return;
    const h1 = h1Ref.current;
    const canvas = canvasRef.current;
    if (!h1 || !canvas) return;
    h1.style.color = "transparent";
    canvas.style.opacity = "1";
  }, [holdForIntro, shaderReady]);

  useEffect(() => {
    if (!playIntro || introRanRef.current) return;
    introRanRef.current = true;

    const wrap = wrapRef.current;
    const h1 = h1Ref.current;
    const canvas = canvasRef.current;
    if (!wrap || !h1) return;

    const inners = h1.querySelectorAll<HTMLElement>(".char-inner");
    if (!inners.length) return;

    if (canvas) canvas.style.opacity = "0";
    h1.style.color = "";
    h1.style.opacity = "1";

    gsap.set(inners, { yPercent: 120, willChange: "transform" });

    wrap.style.visibility = "visible";

    const tl = gsap.timeline();
    tl.to(inners, {
      yPercent: 0,
      duration: 0.82,
      stagger: 0.035,
      ease: "expo.out",
    }).call(
      () => {
        gsap.set(inners, { clearProps: "willChange" });

        redrawRef.current?.();

        h1.style.color = "transparent";
        h1.style.opacity = "1";
        if (canvas) canvas.style.opacity = "1";
        onCompleteRef.current?.();
      },
      undefined,
      "+=0.08",
    );

    return () => {
      tl.kill();
    };
  }, [playIntro]);

  return (
    <div ref={wrapRef} className="relative shrink-0 cursor-default">
      <h1
        ref={h1Ref}
        className="px-4 font-semibold uppercase tracking-[-0.07em] text-black
                   text-4xl sm:px-6 sm:text-5xl md:px-8 md:text-6xl lg:px-10 lg:text-8xl xl:text-8xl 2xl:text-[12rem]"
        style={{ lineHeight: 1 }}
      >
        {HERO_TEXT.split("").map((char, i) => (
          <span
            key={`${char}-${i}`}
            className="char-outer inline-block"
            style={CHAR_OUTER_MASK_STYLE}
          >
            <span className="char-inner inline-block">
              {char === " " ? "\u00A0" : char}
            </span>
          </span>
        ))}
      </h1>
      <canvas
        ref={canvasRef}
        className="pointer-events-none absolute inset-0"
      />
    </div>
  );
}
